-- TABELA PRINCIPAL
CREATE TABLE IF NOT EXISTS sinapi_insumos (
  id           INT AUTO_INCREMENT PRIMARY KEY,
  codigo       VARCHAR(20) NOT NULL,
  descricao    TEXT NOT NULL,
  unidade      VARCHAR(20) NOT NULL,
  tipo         ENUM('INSUMO','COMPOSICAO') NOT NULL,
  preco_unit   DECIMAL(10,4) NOT NULL CHECK(preco_unit >= 0),
  uf           VARCHAR(2) NOT NULL DEFAULT 'SP',
  referencia   VARCHAR(10) NOT NULL DEFAULT '12/2024',
  regime       VARCHAR(20) NOT NULL DEFAULT 'NAO_DESONERADO',
  created_at   TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ÍNDICES para busca rápida (DROP IF EXISTS para idempotência)
DROP INDEX IF EXISTS idx_sinapi_codigo_uf ON sinapi_insumos;
CREATE UNIQUE INDEX idx_sinapi_codigo_uf
  ON sinapi_insumos(codigo, uf, referencia, regime);

DROP INDEX IF EXISTS idx_sinapi_descricao ON sinapi_insumos;
CREATE INDEX idx_sinapi_descricao
  ON sinapi_insumos(descricao(100));

DROP INDEX IF EXISTS idx_sinapi_tipo ON sinapi_insumos;
CREATE INDEX idx_sinapi_tipo
  ON sinapi_insumos(tipo);

-- LIMPAR dados anteriores desta referência (idempotente)
DELETE FROM sinapi_insumos
  WHERE uf='SP' AND referencia='12/2024' AND regime='NAO_DESONERADO';

